import java.io.*;
import java.nio.charset.StandardCharsets;
import java.util.*;

public class Main {
    static class Pair {
        int band;
        long len;
        Pair(int b, long l) { band = b; len = l; }
    }
    public static void main(String[] args) throws Exception {
        // Read entire input as bytes
        byte[] dataBytes = System.in.readAllBytes();
        String data = new String(dataBytes, StandardCharsets.UTF_8);
        // Replace escaped newlines (both "\\n" and "\\\\n") with real newlines
        data = data.replace("\\\\n", "\n");
        data = data.replace("\\n", "\n");
        Scanner sc = new Scanner(new ByteArrayInputStream(data.getBytes(StandardCharsets.UTF_8)));
        StringBuilder sb = new StringBuilder();
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            Map<Integer, List<Long>> map = new HashMap<>();
            for (int i = 0; i < N; i++) {
                int b = sc.nextInt();
                long l = sc.nextLong();
                map.computeIfAbsent(b, k -> new ArrayList<>()).add(l);
            }
            List<Pair> first = new ArrayList<>();
            List<Pair> rest = new ArrayList<>();
            for (Map.Entry<Integer, List<Long>> e : map.entrySet()) {
                List<Long> list = e.getValue();
                Collections.sort(list);
                int band = e.getKey();
                first.add(new Pair(band, list.get(0)));
                for (int i = 1; i < list.size(); i++) {
                    rest.add(new Pair(band, list.get(i)));
                }
            }
            first.sort(Comparator.comparingLong(p -> p.len));
            rest.sort(Comparator.comparingLong(p -> p.len));
            long total = 0L;
            int distinct = 0;
            Set<Integer> seen = new HashSet<>();
            for (Pair p : first) {
                if (!seen.contains(p.band)) {
                    distinct++;
                    seen.add(p.band);
                }
                total += p.len * distinct;
            }
            for (Pair p : rest) {
                total += p.len * distinct; // band already seen
            }
            sb.append(total).append('\n');
        }
        System.out.print(sb.toString());
    }
}

